import{c as a,Q as t,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I trigger a paused release stage?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/trigger-release-stage.md","filePath":"guide/recipes/admin/trigger-release-stage.md","lastUpdated":1779094756000}'),s={name:"guide/recipes/admin/trigger-release-stage.md"};function i(l,e,n,d,g,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="how-do-i-trigger-a-paused-release-stage" tabindex="-1">How do I trigger a paused release stage? <a class="header-anchor" href="#how-do-i-trigger-a-paused-release-stage" aria-label="Permalink to &quot;How do I trigger a paused release stage?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong> (or a SPOC for the stage&#39;s instances, depending on release configuration)</p></div><p>A stage with manual-trigger configuration sits at <code>awaiting_trigger</code> after the previous stage completes. Click <strong>Trigger</strong> to start deploying it.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Releases</strong> and click the release.</li><li>Find the stage in the pipeline — paused stages have a <strong>purple border</strong> and a <strong>Trigger</strong> button.</li><li>Click <strong>Trigger</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The stage moves to <code>deploying</code>. Environment boxes flip to yellow while the rollout runs and green once each environment is deployed.</p><p>If the deploy fails on any environment, the stage moves to <code>failed</code> — review the per-environment logs in the box detail and decide whether to retry, hold, or <a href="./rollback-release">roll back the release</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./approve-release-stage">How do I approve a release stage?</a></li><li><a href="./rollback-release">How do I roll back a release?</a></li></ul>',10)])])}const u=a(s,[["render",i]]);export{h as __pageData,u as default};
